import React, {useState} from "react";
import Navbar from "../components/Navbar";
import styled from "styled-components";
import {Link} from "react-router-dom";

const Container = styled.div`
    width: 100%;
    height: 92vh;
    background-color: #071330;
`;

const Wrapper = styled.div`
    height: 100%;
    display: flex;
    width: 100%;
`;

const InfoContainer = styled.div`
    width: 40%;
    margin-left: 5vw;
    height: 25%;
    display: flex;
    flex-direction: column;
    justify-content: space-between;
`;

const ProjectContainer = styled.div`
    width: 40%;
    margin-left: 5vw;
    display: flex;
    flex-direction: column;
`;

const Info = styled.h2`
    color: white;
`;

const Project = styled.button`
    color: #7BC2BC;
    font-size: 3vh;
    height: 5vh;
`;

const ProjectContent = styled.div`
    background-color: #7BC2BC;
    color: white;
`;
const Home = () => {
    const [collapsedProjects, setCollapsedProjects] = useState({});

    const projects = [
        {name: 'CULTR Magazine', content: 'content'},
        {name: 'Moosic', content: 'content'},
        {name:'27 - Puzzle', content: 'content'},
        {name: 'E20 Processor', content: 'content'},
        {name: 'Piper', content: 'content'},
        {name: 'FlyGenie', content: 'content'},
    ];

    const toggleProject = (project) => {
        setCollapsedProjects((prev) => ({
            ...prev,
            [project]: !prev[project],
        }));
    }

    return (
        <div>
            <Navbar/>
            <Container>
                <Wrapper>
                    <InfoContainer>
                        <Info>Hello, I'm <span style={{color: '#7BC2BC'}}> Joel Harawa</span>, a senior at New York University, passionately immersed in the world of Computer Science.</Info>
                        <Info>I'm an aspiring Software engineer, with interests in both front-end and back-end engineering.</Info>
                    </InfoContainer>
                    <ProjectContainer>
                        <Info><span style={{color: '#7BC2BC'}}>Projects</span></Info>
                        {projects.map((project) => (
                            <div key={project.name}>
                                <Project onClick={() => toggleProject(project.name)}>
                                    {project}
                                </Project>
                                {collapsedProjects[project] && (
                                    <ProjectContent>
                                        {project.content}
                                    </ProjectContent>
                                    )}
                            </div>
                        ))}
                        <Project>CULTR Magazine</Project>

                    </ProjectContainer>
                </Wrapper>
            </Container>
        </div>
    );
}

export default Home;
